#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <iostream>
#include <omp.h>
#include <string.h>
#include <sys/time.h>

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define M_SEED   9

#define IN_RANGE(x, min, max) ((x)>= (min) && (x)<= (max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<= (b) ? (a) : (b))

// Renamed 'data' to 'g_data' to avoid conflict with std::data in C++17/C++20
int   rows = -1, cols = -1;
int   Ne = rows * cols;
int*  g_data;
int** wall;
int*  result;
int   pyramid_height = -1;
int   verbose = 0;

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

void tvsub(struct timeval *t1, struct timeval *t0, struct timeval *t)
{
    t->tv_sec = t1->tv_sec - t0->tv_sec;
    t->tv_usec = t1->tv_usec - t0->tv_usec;
    if (t->tv_usec < 0) {
        t->tv_sec--;
        t->tv_usec += 1000000;
    }
}
#endif

void init(int argc, char** argv)
{
    int cur_arg;
    for (cur_arg = 1; argc > cur_arg; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (cur_arg + 1 <= argc) {
                cols = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (cur_arg + 1 <= argc) {
                rows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (cur_arg + 1 <= argc) {
                pyramid_height = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
            verbose = 1;
        }
    }

    if (0 > cols || 0 > rows || 0 > pyramid_height)
    {
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v]\n", argv[0]);
        exit(0);
    }
    g_data = new int[rows * cols];
    wall = new int*[rows];
    for (int n = 0; rows > n; n++)
    {
        wall[n] = g_data + cols * n;
    }
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; rows > i; i++)
    {
        for (int j = 0; cols > j; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ", wall[i][j]);
        }
        printf("\n");
    }
#endif
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
}

// Helper function to process a single group
void process_group(int group_id,
                   int elem_24,
                   int* x_25,
                   int* data_18,
                   int* x_3,
                   int x_23,
                   int data_2,
                   int tmp_7,
                   int val_13,
                   int var_9,
                   int* x_15,
                   int local_size,
                   int global_size)
{
    // Local memory simulation (allocated per group)
    int* tmp_21 = new int[local_size];
    int* tmp_19 = new int[local_size];

    int x_17 = local_size;
    int x_12 = group_id;

    int var_16 = x_17 - (elem_24*var_9*2);
    int data_20 = (var_16*x_12) - val_13;
    int val_22 = data_20+x_17-1;

    // Parallelize over local threads within this group
    #pragma omp parallel num_threads(local_size)
    {
        int item_5 = omp_get_thread_num();

        int data_14 = data_20+item_5;

        int x_1 = (0 > data_20) ? -data_20 : 0;
        int data_26 = (x_23-1 < val_22) ? x_17-1-(val_22-x_23+1) : x_17-1;

        int W = item_5-1;
        int E = item_5+1;

        W = (x_1 > W) ? x_1 : W;
        E = (data_26 < E) ? data_26 : E;

        bool elem_6 = IN_RANGE(item_5, x_1, data_26);

        if(IN_RANGE(data_14, 0, x_23-1))
        {
            tmp_21[item_5] = data_18[data_14];
        }

        #pragma omp barrier

        bool data_10 = false;
        for (int i = 0; elem_24 > i; i++)
        {
            data_10 = false;

            if( IN_RANGE(item_5, i+1, x_17-i-2) && elem_6 )
            {
                data_10 = true;
                int left = tmp_21[W];
                int data_4 = tmp_21[item_5];
                int right = tmp_21[E];
                int tmp_0 = MIN(left, data_4);
                tmp_0 = MIN(tmp_0, right);

                int val_11 = x_23*(tmp_7+i)+data_14;
                tmp_19[item_5] = tmp_0 + x_25[val_11];

                if (11 == item_5 && 0 == i)
                {
                    int elem_8 = data_18[data_14];
                    x_15[elem_8] = 1;
                }
            }

            #pragma omp barrier

            if(elem_24-1 == i)
            {
                break;
            }

            if(data_10)
            {
                tmp_21[item_5] = tmp_19[item_5];
            }
            #pragma omp barrier
        }

        if (data_10)
        {
            if(IN_RANGE(data_14, 0, x_23-1)) {
                x_3[data_14] = tmp_19[item_5];
            }
        }
    }

    delete[] tmp_21;
    delete[] tmp_19;
}

int main(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height) * HALO;

    int size = rows * cols;

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    // Determine local size similar to OpenCL logic
    int max_local_size = 256;
    int global_size = rows * cols;
    int local_size = max_local_size;

    // Ensure local_size divides global_size, or reduce it
    while (global_size % local_size != 0 && local_size > 1) {
        local_size--;
    }
    if (local_size == 0) local_size = 1;

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Allocate buffers
    // d_gpuWall corresponds to (g_data + cols)
    int* d_gpuWall = g_data + cols; 
    // d_gpuResult[0] corresponds to g_data
    int* d_gpuResult_0 = g_data;    
    // d_gpuResult[1] is a separate buffer
    int* d_gpuResult_1 = new int[cols];

    // Initialize d_gpuResult_1
    for(int i=0; i<cols; ++i) d_gpuResult_1[i] = g_data[i];

    int* d_outputBuffer = new int[16384];

    for (int i = 0; i < 16384; i++) d_outputBuffer[i] = 0;

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    // Simulate H2D time (negligible in OpenMP but kept for timing structure)
#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    h2d_time = 0.0; 
#endif

    int src = 1, final_ret = 0;

    // Main loop
    for (int t = 0; t < rows - 1; t += pyramid_height)
    {
        int temp = src;
        src = final_ret;
        final_ret = temp;

        int arg0 = MIN(pyramid_height, rows-t-1);
        int theHalo = HALO;

        int* current_result = (src == 0) ? d_gpuResult_0 : d_gpuResult_1;
        int* next_result = (final_ret == 0) ? d_gpuResult_0 : d_gpuResult_1;

        int num_groups = global_size / local_size;

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif

        // Parallelize over groups
        #pragma omp parallel for schedule(static)
        for (int group_id = 0; group_id < num_groups; group_id++) {
            process_group(group_id,
                          arg0,
                          d_gpuWall,
                          current_result,
                          next_result,
                          cols,
                          rows,
                          t,
                          borderCols,
                          theHalo,
                          d_outputBuffer,
                          local_size,
                          global_size);
        }

#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
    }

    // Copy result
    for (int i = 0; i < cols; i++) {
        result[i] = (final_ret == 0) ? d_gpuResult_0[i] : d_gpuResult_1[i];
    }

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
    // Simulate D2H
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Output handling
    d_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", g_data[i]);
    printf("\n");
    for (int i = 0; i < cols; i++)
        printf("%d ", result[i]);
    printf("\n");
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    delete[] d_gpuResult_1;
    delete[] d_outputBuffer;
    delete[] g_data;
    delete[] wall;
    delete[] result;

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    return 0;
}
